skeleton:
type: custom:layout-card
layout_type: custom:grid-layout
layout:
  grid-template-columns: 55px 55px 60px 65px 55px 55px 55px 55px 110px 110px
  grid-template-rows: 50px 1fr 1fr 1fr 1fr 1fr 1fr 1fr 1fr 1fr
  gap: 2px
  padding: 0px
cards:

  # NAV BAR
  - type: custom:button-card
    entity: {{NAV_ENTITY}}
    name: Shopping
    tap_action:
      action: call-service
      service: input_select.select_option
      target:
        entity_id: {{NAV_ENTITY}}
      data:
        option: shopping
    view_layout:
      grid-column: 1 / 4
      grid-row: 1

  - type: custom:button-card
    entity: {{NAV_ENTITY}}
    name: Stock
    tap_action:
      action: call-service
      service: input_select.select_option
      target:
        entity_id: {{NAV_ENTITY}}
      data:
        option: stock
    view_layout:
      grid-column: 4 / 7
      grid-row: 1

  - type: custom:button-card
    entity: {{NAV_ENTITY}}
    name: Tasks
    tap_action:
      action: call-service
      service: input_select.select_option
      target:
        entity_id: {{NAV_ENTITY}}
      data:
        option: tasks
    view_layout:
      grid-column: 7 / 10
      grid-row: 1

  # CONTENT AREA
  - type: custom:layout-card
    layout_type: custom:grid-layout
    layout:
      grid-template-columns: 1fr
      grid-template-rows: 1fr
    view_layout:
      grid-column: 1 / 11
      grid-row: 2 / 11
    cards:

      # Shopping — product image cards
      - type: conditional
        conditions:
          - condition: state
            entity: {{NAV_ENTITY}}
            state: shopping
        card:
          type: custom:auto-entities
          show_empty: false
          card:
            type: grid
            square: false
            columns: 4
          card_param: cards
          filter:
            template: >
              {% set items = state_attr('{{SHOPPING_LIST_SENSOR}}', 'products') %}
              {% set pics = state_attr('{{PRODUCT_PICTURES_SENSOR}}', 'pictures') or [] %}
              {% if items is iterable and items | count > 0 %}
                {% for item in items if not item.done %} {% set pic = pics | selectattr('id','eq', item.product_id) | list | first | default(none) %} {% set img = pic.image if pic else '' %} {{
                  {
                    "type": "custom:button-card",
                    "name": item.product.name,
                    "show_icon": false,
                    "card_mod": {"style": "ha-card { background-image: url('" + img + "') !important; background-size: cover !important; background-position: center !important; border-radius: 10px; height: 80px; }"}
                  }
                }}, {% endfor %}
              {% endif %}

      # Stock — todo-list with dense styling
      - type: conditional
        conditions:
          - condition: state
            entity: {{NAV_ENTITY}}
            state: stock
        card:
          type: todo-list
          entity: {{STOCK_TODO}}
          display_order: duedate_asc
          card_mod:
            style:
              .: |
                ha-card.type-todo-list div.header { display: none; }
                ha-check-list-item.editRow.completed { display: none; }
                .divider { display: none; }
                ha-check-list-item { min-height: 28px !important; }
                ha-icon-button.reorderButton, ha-icon-button.addButton { margin-top: -35px !important; }
                :host {
                  height: 580px !important;
                  overflow-y: scroll !important;
                  overflow-x: hidden !important;
                  display: block !important;
                }
              ha-textfield:
                $: |
                  .mdc-text-field { margin-top: -28px; height: 50px !important; }
                  .mdc-text-field__input { color: white !important; }

      # Tasks — todo-list clean
      - type: conditional
        conditions:
          - condition: state
            entity: {{NAV_ENTITY}}
            state: tasks
        card:
          type: todo-list
          entity: {{TASKS_TODO}}
          card_mod:
            style:
              .: |
                ha-card.type-todo-list div.header { display: none; }
                ha-check-list-item.editRow.completed { display: none; }
                :host {
                  height: 580px !important;
                  overflow-y: scroll !important;
                  overflow-x: hidden !important;
                  display: block !important;
                }
